@namespace Lumeo
@implements IAsyncDisposable
@inject Lumeo.Services.ConsentService Consent
@inject IComponentInteropService Interop

@if (_ready && !Consent.HasDecided && !_preferencesOpen)
{
    @* Non-modal: the banner is dismissible without trapping the page, so it
       uses role="region" rather than role="dialog". Only the preferences
       overlay below is a true aria-modal dialog. *@
    <div id="@_bannerId" role="region" aria-labelledby="@_titleId" aria-describedby="@_descId"
         class="@(Cx.Merge("lumeo-consent-banner fixed bottom-4 left-1/2 -translate-x-1/2 w-[calc(100%-2rem)] max-w-2xl z-50", AnimationClass, Class))"
         @attributes="AdditionalAttributes">
        <div class="rounded-lg border border-border/60 bg-popover text-popover-foreground shadow-xl p-5">
            <div class="flex flex-col gap-4 md:flex-row md:items-start">
                <div class="flex-1 min-w-0">
                    <div class="flex items-center gap-2 mb-1">
                        <SvgGlyph Svg="@(LumeoIcons.Cookie)" class="h-4 w-4 text-primary" />
                        <h3 id="@_titleId" class="text-sm font-semibold">@Title</h3>
                    </div>
                    <p id="@_descId" class="text-sm text-muted-foreground leading-relaxed">
                        @Description
                        @if (!string.IsNullOrEmpty(PrivacyPolicyUrl))
                        {
                            <text> </text>
                            <a href="@PrivacyPolicyUrl" class="text-primary hover:underline">@PrivacyPolicyLabel</a>
                            <text>.</text>
                        }
                    </p>
                </div>
                <div class="flex w-full flex-col gap-2 sm:w-auto sm:flex-row sm:flex-wrap sm:items-center sm:shrink-0">
                    @if (EffectiveCategories.Any(c => !c.Required))
                    {
                        <button type="button"
                                class="inline-flex items-center justify-center rounded-md text-xs font-medium w-full sm:w-auto h-8 px-3 text-muted-foreground hover:text-foreground transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2"
                                @onclick="OpenPreferences">
                            @CustomizeLabel
                        </button>
                    }
                    @* Reject and Accept carry EQUAL visual weight by default (identical
                       classes, same size/variant) so the banner never nudges toward
                       accepting — GDPR / EDPB guidance requires the reject action to be
                       no less prominent than accept. Restyle both via CSS if you want a
                       primary accent, but keep them symmetric. *@
                    <button type="button"
                            class="@Layer1ActionClass"
                            @onclick="RejectAll">
                        @RejectLabel
                    </button>
                    <button type="button"
                            class="@Layer1ActionClass"
                            @onclick="AcceptAll">
                        @AcceptLabel
                    </button>
                </div>
            </div>
        </div>
    </div>
}

@if (_preferencesOpen)
{
    <div id="@_prefDialogId" role="dialog" aria-modal="true" aria-labelledby="@_prefTitleId" aria-describedby="@_prefDescId"
         tabindex="-1"
         @onkeydown="HandlePrefKeyDown" @onkeydown:stopPropagation="true"
         class="fixed inset-0 z-50 flex items-center justify-center p-4 bg-background/70 backdrop-blur-sm animate-fade-in">
        <div class="w-full max-w-lg rounded-lg border border-border/60 bg-popover text-popover-foreground shadow-2xl">
            <div class="p-6 border-b border-border/40">
                <h3 id="@_prefTitleId" class="text-lg font-semibold">@PreferencesTitle</h3>
                <p id="@_prefDescId" class="text-sm text-muted-foreground mt-1 leading-relaxed">@PreferencesDescription</p>
            </div>

            <div class="p-6 space-y-4 max-h-[50vh] overflow-y-auto">
                @foreach (var cat in EffectiveCategories)
                {
                    var catKey = cat.Key;
                    var locked = cat.Required;
                    var checkedValue = IsDraftChecked(cat);
                    var labelClass = locked ? "opacity-70 cursor-not-allowed" : "";
                    <label class="@($"flex items-start gap-3 cursor-pointer {labelClass}")">
                        <div class="mt-0.5 shrink-0">
                            <input type="checkbox"
                                   class="peer inline-flex items-center justify-center h-4 w-4 shrink-0 cursor-pointer rounded border border-primary/60 transition-colors checked:bg-primary checked:border-primary disabled:cursor-not-allowed disabled:opacity-50"
                                   checked="@checkedValue"
                                   disabled="@locked"
                                   @onchange="@(e => ToggleCategory(catKey, e))" />
                        </div>
                        <div class="flex-1 min-w-0">
                            <div class="flex items-center gap-2">
                                <span class="text-sm font-medium text-foreground">@cat.Title</span>
                                @if (locked)
                                {
                                    <span class="text-[10px] uppercase tracking-wider text-muted-foreground font-semibold">@RequiredBadge</span>
                                }
                            </div>
                            <p class="text-xs text-muted-foreground mt-0.5 leading-relaxed">@cat.Description</p>
                        </div>
                    </label>
                }
            </div>

            <div class="p-6 border-t border-border/40 flex items-center justify-end gap-2">
                <button type="button"
                        class="inline-flex items-center justify-center rounded-md text-xs font-medium h-8 px-3 text-muted-foreground hover:text-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2"
                        @onclick="ClosePreferencesNoSave">
                    @CancelLabel
                </button>
                <button type="button"
                        class="inline-flex items-center justify-center rounded-md text-xs font-medium h-8 px-3 border border-border/60 bg-background hover:bg-accent"
                        @onclick="RejectAll">
                    @RejectLabel
                </button>
                <button type="button"
                        class="inline-flex items-center justify-center rounded-md text-xs font-medium h-8 px-3 bg-primary text-primary-foreground hover:bg-primary/90 focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2"
                        @onclick="SavePreferences">
                    @SaveLabel
                </button>
            </div>
        </div>
    </div>
}

@code {
    /// <summary>Additional CSS classes merged onto the banner's root <c>role="region"</c> element (the preferences dialog is unaffected).</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Unmatched attributes splatted onto the banner's root <c>role="region"</c> element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    /// <summary>Consent buckets to expose in the preferences dialog. Omit `Required: true` ones if your site doesn't use strictly-necessary cookies.</summary>
    [Parameter] public IReadOnlyList<Lumeo.Services.ConsentCategory> Categories { get; set; } = DefaultCategories;

    // Categories is declared non-nullable, but a consumer can still push null
    // through the parameter setter (e.g. an unresolved binding). Coalesce to the
    // default set everywhere we enumerate it so a transiently-null binding renders
    // the defaults instead of NRE-ing on every render / dialog open.
    private IReadOnlyList<Lumeo.Services.ConsentCategory> EffectiveCategories => Categories ?? DefaultCategories;

    /// <summary>URL to your privacy policy page. If null, the link is hidden.</summary>
    [Parameter] public string? PrivacyPolicyUrl { get; set; }

    /// <summary>
    /// Privacy-policy version this banner asks consent for. When a stored decision was
    /// recorded against a different version, the banner re-prompts (previous choices
    /// prefill the preferences dialog, but the user must re-confirm). Bump this whenever
    /// your policy materially changes. Defaults to <c>"1"</c>.
    /// </summary>
    [Parameter] public string PolicyVersion { get; set; } = "1";

    // Shared class for the layer-1 Reject/Accept buttons. Referenced by BOTH so they
    // are guaranteed identical — equal visual weight, no accept-nudge (see markup note).
    private const string Layer1ActionClass =
        "inline-flex items-center justify-center rounded-md text-xs font-medium w-full sm:w-auto h-8 px-3 border border-border/60 bg-background hover:bg-accent transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2";

    // ---------- Copy — every string is overridable for i18n / tone. ----------
    /// <summary>Banner heading, shown next to the cookie icon.</summary>
    [Parameter] public string Title { get; set; } = "Cookies & consent";
    /// <summary>Banner body text, followed by the privacy-policy link when <see cref="PrivacyPolicyUrl"/> is set.</summary>
    [Parameter] public string Description { get; set; } = "We use a minimal set of cookies to run the site and optionally measure anonymous usage to improve it. You choose what's on.";
    /// <summary>Link text for the privacy-policy link (only shown when <see cref="PrivacyPolicyUrl"/> is set).</summary>
    [Parameter] public string PrivacyPolicyLabel { get; set; } = "Read the privacy policy";
    /// <summary>Label for the layer-1 "accept everything" button.</summary>
    [Parameter] public string AcceptLabel { get; set; } = "Accept all";
    /// <summary>Label for the layer-1 "reject optional categories" button.</summary>
    [Parameter] public string RejectLabel { get; set; } = "Reject optional";
    /// <summary>Label for the button that opens the preferences dialog; only rendered when at least one non-required category exists.</summary>
    [Parameter] public string CustomizeLabel { get; set; } = "Customize";
    /// <summary>Heading of the preferences dialog.</summary>
    [Parameter] public string PreferencesTitle { get; set; } = "Consent preferences";
    /// <summary>Body text of the preferences dialog.</summary>
    [Parameter] public string PreferencesDescription { get; set; } = "Pick which categories you're okay with. You can change this later.";
    /// <summary>Badge text shown next to a category that is <c>Required: true</c> (always on, not toggleable).</summary>
    [Parameter] public string RequiredBadge { get; set; } = "Required";
    /// <summary>Label for the preferences dialog's cancel button (discards draft changes).</summary>
    [Parameter] public string CancelLabel { get; set; } = "Cancel";
    /// <summary>Label for the preferences dialog's save button (commits the draft toggles).</summary>
    [Parameter] public string SaveLabel { get; set; } = "Save preferences";

    /// <summary>CSS animation class applied to the banner on mount (default a slide-in from the bottom edge).</summary>
    [Parameter] public string AnimationClass { get; set; } = "animate-slide-in-from-bottom";

    private static readonly IReadOnlyList<Lumeo.Services.ConsentCategory> DefaultCategories = new[]
    {
        new Lumeo.Services.ConsentCategory("necessary", "Strictly necessary", "Required for the site to function — theme preference, routing state, session.", Required: true),
        new Lumeo.Services.ConsentCategory("analytics",  "Analytics",         "Anonymous aggregate stats on which pages are visited, so we know what to improve."),
    };

    private readonly string _titleId = LumeoIds.New("lumeo-consent-title");
    private readonly string _descId  = LumeoIds.New("lumeo-consent-desc");
    private readonly string _bannerId = LumeoIds.New("lumeo-consent-banner");
    private readonly string _prefTitleId = LumeoIds.New("lumeo-consent-pref-title");
    private readonly string _prefDescId = LumeoIds.New("lumeo-consent-pref-desc");
    private readonly string _prefDialogId = LumeoIds.New("lumeo-consent-pref-dialog");

    private bool _ready;
    private bool _preferencesOpen;
    // True once Interop.AttachOverlaySlideEnd has been wired for the currently
    // mounted banner instance. Reset whenever the banner unmounts (decision
    // made, or the preferences dialog covers it) so a later re-prompt — a
    // fresh DOM node replaying the entrance animation — gets rewired instead
    // of silently skipping the cleanup.
    private bool _slideEndWired;
    // True while the preferences dialog has an active scroll-lock + focus-trap
    // installed. Driven from OnAfterRenderAsync so the JS calls run once the
    // dialog (or its absence) is in the DOM. SetupFocusTrap focuses the first
    // focusable element on open and restores focus to the trigger on removal
    // (WCAG 2.4.3), so the manual Save-button focus dance is no longer needed.
    private bool _prefModalActive;
    private Dictionary<string, bool> _draft = new(StringComparer.OrdinalIgnoreCase);

    protected override void OnInitialized()
    {
        Consent.OnChange += HandleConsentChange;
        Consent.OnRequestOpenPreferences += HandleReopenRequest;
    }

    protected override void OnParametersSet()
    {
        // Push the configured policy version into the service on EVERY parameter set, not
        // just once in OnInitialized: a PolicyVersion supplied later — resolved async, or
        // changed by the parent after first render — must still reach the service. The
        // setter is idempotent (an unchanged value is a no-op) and re-evaluates a
        // hydrated decision's validity when the version actually changes, so pushing it
        // here is safe on the first render (runs before EnsureLoadedAsync in
        // OnAfterRenderAsync, so a mismatch is still detected on load) and on every later one.
        Consent.PolicyVersion = PolicyVersion;
    }

    private void HandleReopenRequest() => InvokeAsync(() =>
    {
        OpenPreferences();
        StateHasChanged();
    });

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            try
            {
                await Consent.EnsureLoadedAsync();
                _ready = true;
                StateHasChanged();
            }
            catch (JSDisconnectedException) { }
            catch (ObjectDisposedException) { }
        }

        // Held-fill guard: the banner's root carries AnimationClass (default
        // animate-slide-in-from-bottom) with animation-fill-mode:both, which
        // never resolves on its own — the same "Toast bug class" pattern fixed
        // for Sheet/Drawer/Dialog/AlertDialog via Interop.AttachOverlaySlideEnd.
        // Left unfixed, a transform-animating class stays live on the element
        // forever, permanently establishing a containing block for any
        // position:fixed descendant. Wire it once per mounted instance, and
        // only for the slide/zoom families AttachOverlaySlideEnd actually
        // targets — a consumer-supplied fade/none AnimationClass must not be
        // touched, since the JS unconditionally stamps animation:none when it
        // finds no matching animation, which would cut a fade-in short.
        //
        // MUST be gated on `!firstRender`: on the first call, `_ready` flips
        // false->true above and StateHasChanged() only QUEUES the follow-up
        // render — it does not block until the DOM is updated. Attaching here,
        // in the same firstRender pass, would target a `role="region"` element
        // that doesn't exist yet: document.getElementById returns null, the JS
        // attach is a silent no-op, and (before this fix) _slideEndWired was
        // still latched true, permanently skipping the retry. Sheet/Dialog
        // dodge this because their open-flag flips via a PARENT parameter
        // change (OnParametersSetAsync -> render -> OnAfterRenderAsync), so by
        // the time their OnAfterRenderAsync runs, the render has already
        // committed. Here the flag flips from inside OnAfterRenderAsync itself,
        // so we defer one render — the render that actually mounts the banner
        // is the very next OnAfterRenderAsync(firstRender: false) call, queued
        // by the StateHasChanged() above (or by HandleConsentChange /
        // ClosePreferencesNoSave for later banner appearances).
        bool bannerVisible = _ready && !Consent.HasDecided && !_preferencesOpen;
        if (!firstRender && bannerVisible && !_slideEndWired && IsSlideOrZoomAnimation(AnimationClass))
        {
            _slideEndWired = true;
            try { await Interop.AttachOverlaySlideEnd(_bannerId); }
            catch (JSDisconnectedException) { }
        }
        else if (!bannerVisible && _slideEndWired)
        {
            _slideEndWired = false;
        }

        // Drive the modal a11y primitives off the open/closed transition.
        if (_preferencesOpen && !_prefModalActive)
        {
            _prefModalActive = true;
            try
            {
                await Interop.LockScroll();
                await Interop.SetupFocusTrap(_prefDialogId);
            }
            catch (JSDisconnectedException) { }
        }
        else if (!_preferencesOpen && _prefModalActive)
        {
            _prefModalActive = false;
            await TeardownPrefModal();
        }
    }

    private async Task TeardownPrefModal()
    {
        try
        {
            await Interop.RemoveFocusTrap(_prefDialogId);
            await Interop.UnlockScroll();
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
    }

    private async Task HandlePrefKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Escape")
        {
            await ClosePreferencesNoSave();
        }
    }

    private void HandleConsentChange() => InvokeAsync(StateHasChanged);

    private async Task AcceptAll()
    {
        await Consent.AcceptAllAsync(EffectiveCategories.Where(c => !c.Required).Select(c => c.Key));
        _preferencesOpen = false;
    }

    private async Task RejectAll()
    {
        await Consent.RejectAllAsync(EffectiveCategories.Where(c => !c.Required).Select(c => c.Key));
        _preferencesOpen = false;
    }

    private void OpenPreferences()
    {
        // Only seed the draft on a genuine closed->open transition. A redundant
        // reopen request (ConsentService.RequestOpenPreferences fired again, or
        // ShowPreferences() called) while the dialog is already open must NOT
        // re-seed, otherwise the user's in-progress (unsaved) toggle edits are
        // silently discarded.
        if (!_preferencesOpen)
        {
            // Seed the draft from current consent so the toggles reflect reality.
            // Build defensively rather than ToDictionary: two ConsentCategory entries
            // sharing a Key (case-insensitively, since the dictionary is
            // OrdinalIgnoreCase) would make ToDictionary throw and tear down the
            // circuit. Last-wins keeps the dialog openable for misconfigured inputs.
            // Seed from the STORED snapshot rather than HasConsent: during a
            // version-mismatch re-prompt HasConsent reports false (consent pending),
            // but the dialog must still prefill the user's previous choices.
            var snap = Consent.Snapshot();
            var draft = new Dictionary<string, bool>(StringComparer.OrdinalIgnoreCase);
            foreach (var c in EffectiveCategories)
                draft[c.Key] = c.Required || (snap.TryGetValue(c.Key, out var v) && v);
            _draft = draft;
        }
        _preferencesOpen = true;
    }

    // Mirrors the filter attachOverlaySlideEnd applies in components.js
    // (animationName startsWith 'slide-in-from-' or === 'zoom-in') so we only
    // wire the interop for classes it can actually resolve a fill-mode:both
    // transform animation on.
    private static bool IsSlideOrZoomAnimation(string? animationClass) =>
        animationClass is not null
        && (animationClass.Contains("slide-in-from-", StringComparison.Ordinal)
            || animationClass.Contains("animate-zoom-in", StringComparison.Ordinal));

    /// <summary>Public entry point so a "Manage cookie preferences" link anywhere in the layout can reopen the dialog.</summary>
    public void ShowPreferences()
    {
        OpenPreferences();
        StateHasChanged();
    }

    private Task ClosePreferencesNoSave()
    {
        _preferencesOpen = false;
        return Task.CompletedTask;
    }

    private bool IsDraftChecked(Lumeo.Services.ConsentCategory cat)
    {
        if (cat.Required) return true;
        return _draft.TryGetValue(cat.Key, out var v) && v;
    }

    private void ToggleCategory(string key, ChangeEventArgs e)
    {
        if (e.Value is bool b) _draft[key] = b;
    }

    private async Task SavePreferences()
    {
        await Consent.SetManyAsync(_draft);
        _preferencesOpen = false;
    }

    public async ValueTask DisposeAsync()
    {
        Consent.OnChange -= HandleConsentChange;
        Consent.OnRequestOpenPreferences -= HandleReopenRequest;
        // If the circuit tears down while the prefs dialog is open, release the
        // scroll lock + focus trap so they don't leak into the next page.
        if (_prefModalActive)
        {
            _prefModalActive = false;
            await TeardownPrefModal();
        }
    }
}
